import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';

const Upcoming = () => {
  const [page,setPage]=useState(1);
  const [UpcomingMovieList,setUpcomingMovieList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> prev + 1);
   refetch();
   setUpcomingMovieList((prev)=> [...prev,...upcoming]);
   console.log(UpcomingMovieList);
 }

  const { isLoading,isError,error ,data: upcoming,refetch} = useQuery({
      queryKey: ["Movie", "upcoming"],
      queryFn: () =>
        fetchMovie("upcoming",`${page}`).then((res) => {
          setUpcomingMovieList(res.results)
          return res.results;
        }),
    });



    useEffect(()=>{
      // refetch();
      return()=>{
        refetch();
      }
    },[refetch,page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
   return (
  <div className="Popular">
        <h1>Upcoming Movies</h1>
        <div>
        {UpcomingMovieList?.map((item,index) => (
            <Link to={`/movie/${item.id}`} className="card" key={index}>
              <img src={`${Img_URL}${item.poster_path}`} alt="img" />
            </Link>
        ))}
        </div>
        <button onClick={loadMoreHandle}>More</button>
      </div>
)
}

export default Upcoming
